import { useState, useEffect } from "react";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Autocomplete,
  Chip,
} from "@mui/material";
import { Edit } from "@mui/icons-material";
import DeleteIcon from "@mui/icons-material/Delete";

import API from "../../api/axios";

export default function ProjectManagement() {
  const [search, setSearch] = useState("");
  const [data, setData] = useState([]);
  const [users, setUsers] = useState([]);

  const [editOpen, setEditOpen] = useState(false);
  const [editData, setEditData] = useState(null);

  const [assignOpen, setAssignOpen] = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);
  const [selectedUsers, setSelectedUsers] = useState([]);

  // 🔄 FETCH PROJECTS
  const fetchProjects = async () => {
    try {
      const res = await API.get("projects/");
      setData(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // 🔄 FETCH USERS
  const fetchUsers = async () => {
    try {
      const res = await API.get("users/");
      setUsers(res.data);
    } catch (err) {
      console.log("User API error:", err);
      setUsers([]);
    }
  };

  useEffect(() => {
    fetchProjects();
    fetchUsers();
  }, []);

  // ✏️ UPDATE PROJECT
  const updateProject = async () => {
    try {
      await API.put(`projects/${editData.id}/`, editData);
      setEditOpen(false);
      fetchProjects();
    } catch (err) {
      console.log(err);
    }
  };

  // 🗑 DELETE PROJECT
  const deleteProject = async (id) => {
    if (!window.confirm("Delete project?")) return;

    try {
      await API.delete(`projects/${id}/delete/`);
      fetchProjects();
    } catch (err) {
      console.log(err);
      alert("Delete failed ❌");
    }
  };

  // ➕ ASSIGN MULTIPLE USERS
  const assignUserToProject = async () => {
    try {
      await API.post("assign-user/", {
        project_id: selectedProject.id,
        user_ids: selectedUsers.map((u) => u.id),
      });

      setAssignOpen(false);
      setSelectedUsers([]);
      fetchProjects();
    } catch (err) {
      console.log(err);
      alert("Assign failed ❌");
    }
  };

  const removeUserFromProject = async (projectId, userId) => {
    try {
      await API.post("remove-user/", {
        project_id: projectId,
        user_id: userId,
      });

      fetchProjects(); // refresh
    } catch (err) {
      console.log(err);
      alert("Remove failed ❌");
    }
  };

  return (
    <Box sx={{ p: 4, display: "flex", justifyContent: "center" }}>
      <Paper sx={{ width: "100%", maxWidth: 1200, p: 4, borderRadius: 4 }}>
        {/* HEADER */}
        <Typography variant="h5" fontWeight="bold" mb={3}>
          Project Management
        </Typography>

        {/* SEARCH */}
        <TextField
          fullWidth
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ mb: 3 }}
        />

        {/* TABLE */}
        <Table>
          <TableHead>
            <TableRow>
              {[
                "Project",
                "Users",
                "Description",
                "Start",
                "End",
                "Actions",
              ].map((h) => (
                <TableCell>
                  {Array.isArray(row.users) && row.users.length > 0
                    ? row.users.map((u) => (
                        <Chip
                          key={u.id}
                          label={u.username}
                          onDelete={() => removeUserFromProject(row.id, u.id)} // 🔥 remove
                          sx={{ mr: 1, mb: 1 }}
                        />
                      ))
                    : "-"}
                </TableCell>
              ))}
            </TableRow>
          </TableHead>

          <TableBody>
            {data
              .filter((d) =>
                d.project_name?.toLowerCase().includes(search.toLowerCase()),
              )
              .map((row) => (
                <TableRow key={row.id}>
                  <TableCell>{row.project_name}</TableCell>

                  {/* 👥 MULTIPLE USERS */}
                  <TableCell>
                    {Array.isArray(row.users)
                      ? row.users.map((u) => u.username).join(", ")
                      : row.user}
                  </TableCell>

                  <TableCell>{row.description}</TableCell>
                  <TableCell>{row.start}</TableCell>
                  <TableCell>{row.end}</TableCell>

                  {/* ACTIONS */}
                  <TableCell>
                    {/* EDIT */}
                    <IconButton
                      onClick={() => {
                        setEditData(row);
                        setEditOpen(true);
                      }}
                    >
                      <Edit />
                    </IconButton>

                    {/* ➕ ADD USER */}
                    <IconButton
                      onClick={() => {
                        setSelectedProject(row);
                        setAssignOpen(true);
                      }}
                      sx={{ color: "#2e7d32" }}
                    >
                      ➕
                    </IconButton>

                    {/* DELETE */}
                    <IconButton onClick={() => deleteProject(row.id)}>
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
          </TableBody>
        </Table>

        {/* ✏️ EDIT MODAL */}
        <Dialog open={editOpen} onClose={() => setEditOpen(false)} fullWidth>
          <DialogTitle>Edit Project</DialogTitle>

          <DialogContent>
            <TextField
              fullWidth
              label="Project Name"
              value={editData?.project_name || ""}
              onChange={(e) =>
                setEditData({ ...editData, project_name: e.target.value })
              }
            />
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setEditOpen(false)}>Cancel</Button>
            <Button variant="contained" onClick={updateProject}>
              Update
            </Button>
          </DialogActions>
        </Dialog>

        {/* ➕ ASSIGN MULTI USER MODAL */}
        <Dialog
          open={assignOpen}
          onClose={() => setAssignOpen(false)}
          fullWidth
        >
          <DialogTitle>Assign Users</DialogTitle>

          <DialogContent
            sx={{ display: "flex", flexDirection: "column", gap: 2 }}
          >
            <Typography>
              Project: <b>{selectedProject?.project_name}</b>
            </Typography>

            <Autocomplete
              multiple
              options={users}
              getOptionLabel={(option) => option.username}
              value={selectedUsers}
              onChange={(e, newValue) => setSelectedUsers(newValue)}
              renderTags={(value, getTagProps) =>
                value.map((option, index) => (
                  <Chip
                    label={option.username}
                    {...getTagProps({ index })}
                    key={option.id}
                  />
                ))
              }
              renderInput={(params) => (
                <TextField {...params} label="Select Users" />
              )}
            />
          </DialogContent>

          <DialogActions>
            <Button onClick={() => setAssignOpen(false)}>Cancel</Button>
            <Button variant="contained" onClick={assignUserToProject}>
              Assign
            </Button>
          </DialogActions>
        </Dialog>
      </Paper>
    </Box>
  );
}
